  "verses": [
    {
      "n": 4,
      "column": "left",
      "text": "Bet ja ar weenu tohp trum-\nmetehts/ tad buhs teem Leeleem-\nRungeem / teem Wirfneekeem\npahr Israëka tuhksfofcheem pee\ntew fapulzetees.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Kad juhs ar laustu Skannu\ntrummetat / tad buhs teem Leh-\ngereem zeltees/ kas prett Rihteem\napmettabs.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Bet kad juhs ohtran Kahr-\ntan ar laustu Skannu trumme-\ntat / tad buhs teem Lehgereem\nzeltees/ kas prett Deenas-Widdu\napinettahs / ar laustu Skannu\nbuhs teem trummeteht / kad wix-\nneem jazellahs.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Bet to Draudsi fapulzena-\nDamı buhs jums trummeteht / to-\nmebr ne ar laustu Skannu.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Un teem Aäreza Dehleem\nteem Preestexeem/ buhs ar tahm\nTrummetchın trummeteht/ un tas\nlaid junster par weenu Eikunnu\nmuhschain / pee juhsfu Pehznah-\nkameem.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Un kad juhs fawa Seimmē\nKarrā eeseet / prett juhsfu Eenaid-\nneekem/kas juhs speesch/tad buhs\njums ar laustu Skannu trumme-\nteht / tad buhs juhsfu Beeminne-\nSchana preefsch ta KUNGA juhsfu\nDeewa/ un juhs tapfeet tsglahb-\nti no juhsfeem Eenaidneekfeem.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Un juhsfu Eihasinthas\nLaikā / un juhsfs Swehtfs /\nun juhsfs jaunds Mehneschos /\nbuhs jums arridsan ar tahm\nTrummetehın trummeteht/ pahr\njuhsfeem Dedsameem-Uppureem /\nun pahr juhsfeem Pateteschanns-\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Uppureitt / un teem buhs jum\npar Beeminneschann buht/preeksf\njuhsfu Deewa. Es efmu ta\nKUNGS juhsfu Deews.\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Un tas notikke ohtrā Gad\ndā/ ohtrā Mehneti / diwidermitt\nMehnes Deenā / iezehlabs t\nPadebbes no ta Leezibas Dsil\nwokta.\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Un tee Israëka Behrni zeh\nlahs pehz faweem Zelta-Gabju\nmeem / no tahs Tuksnefes Sinā\nun ta Padebbes palikke Pahran\nTuksneti.\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Ta zehlabs tee pirni\nKahrtā pehz ta KUNGA Wahrd\nu/ zaur Mohsu.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Jo us preefschu zehlabs\nto Juha Behrnu Lehgera Kar\nrohgś/ pehz faweem Pulkeem / u\npahr wiakka Spehku bija Naē\nsons/ Amminadaba Dehls.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Un pahr to Ibsafchar\nBehrnu Zilts Spehku bija Na-\ntaneēls/ Zuara Dehls.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Un par to Sebulana Behr\nnn Zilts Spehku bija Eeliabs\nEelena Dehls.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Ta tappe tas Dsilhwokli\nnozelts / un tee Gersona Behrni\nun tee Merara Behrni zehlabs\nnesdanni to Dsilhwokli.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Pehz to zehlabs ta Ru-\nbena Lehgera Karrohgs pehz fa\nweem Pulkeem / un pahr winn\nSpehku bija Gelizurs / Sedeiu\nDehls.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Un pahr to Sihuneaz-\nBehrnu Zilts Spehku bija Selu\nntiels / ZuriSadaja Dehls.\n"
    }
  ],
  "confidence": "high",
